form:Form.form:Scripts:
		var CLASS_TREE = null;
var item_selected = null;
function OnLoad()
{    	
	NomadTimeout("Load();", 25, "Cargando mensajes...");	  			
}

function LoadEmpty(objTREE, objGROUP)
{
	objTREE.SetXML(objGROUP.FullId,"<TREE/>")
}

function Load()
{	
	onLoad();
	var np = GetProxy();
	var nSQL = np.SQLService();

	var resultxt=nSQL.Get(Ctrl("main").getResource("qry:folders"), "<PARAM entity=\""+np.Etty()+"\"/>");	
	CLASS_TREE=clsClientTree("contFOLDERS","itemid","CLOCK.ico","folder-close.ico","folder.ico","folder.ico",false,LoadEmpty,null,showMail);
	CLASS_TREE.SetXML(null, resultxt);	
	CLASS_TREE.ClickExpGroup('1'); 

	if (item_selected != null)
	{		
		CLASS_TREE.SetSelectedId(item_selected.FullId);
		showMail(CLASS_TREE, item_selected);		
	}	
}

function showMail(tree, item)
{	
	var np = GetProxy();
	var nSQL = np.SQLService(); 		

	item_selected = item;
	var id_folder = item.Id;
	var file = item.Tag;			
	var xQry = nSQL.Get(Ctrl("main").getResource("qry:mails"), "<PARAM entity=\"" + np.Etty() + "\" file=\"" + file + "\" id-folder=\"" + id_folder + "\" />");

	Ctrl("mails").processResult(xQry);
}

function ViewMail()
{
	item_selected = CLASS_TREE.GetItem(Ctrl('itemid').GetXValue());
	if(Ctrl("mails").TotalRowsCount() >0)
	{
		Ctrl("mails").SetSelectAttrValue("img",'Listas/emailopen.gif');	
		UnRead();				
		NomadTimeout('getFormInMain("Nomad.Base.Mail.InputMails.flow","initialize","<MAIL id=\\\"' + Ctrl("mails").GetXValue() + '\\\"/>", false);', 1000, "Abriendo correo...");		
	}
	else
	{
		alert("No hay ningun mensaje seleccionado");
	}      	
}

function NewMail()
{ 
	getFormInMain("Nomad.Base.Mail.OutputMails.flow","NEW","", false);	
}

function DelMail()
{
	item_selected = CLASS_TREE.GetItem(Ctrl('itemid').GetXValue());
	if(Ctrl("mails").TotalRowsCount() >0)
	{		
	  if (Ctrl("mails").GetSelectAttrValue("img") == 'Listas/email.gif')
	  {
			UnRead();	  
	  }        	  	  
	  NomadTimeout("Del();", 100, "Eliminando correo...");	  			
	}
	else
	{
		alert("No hay ningun mensaje seleccionado");
	}	
} 

function Del()
{
		//Cargo el metodo
		var proxy=new NomadProxy();
		var RPC=new NomadXML(proxy.DDOService().Get("Nomad.Base.Mail.InputMails.MAIL", Ctrl("mails").GetXValue()));
		RPC.SetAttr("nmd-status","~d,");
		RPC.FirstChild().SetAttr("nmd-status","~d,");
		proxy.DDOService().Set("Nomad.Base.Mail.InputMails.MAIL", RPC.ToString());				
		showMail(CLASS_TREE, item_selected);		
}

function UnRead()
{ 		
		var spl = item_selected.Label.split("(");
		if(spl.length>1)
		{		
			count = spl[spl.length - 1];
			count =  parseInt(count.substr(0,count.length - 1)) - 1;		

			spl.length--;				
			if (count !=0)
			{			
				item_selected.Label = spl.join("(") + "(" + count.toString() + ")";

			}
			else
			{
				item_selected.Label = spl.join("(");
			}
		}
		CLASS_TREE.Draw("1");
}
